content.text:
 1	.odc-task-list-node {
 2	  border: 1px solid var(--pf-t--global--border--color--100);
 3	
 4	  &__container {
 5	    overflow: hidden;
 6	    box-shadow: var(--pf-v6-c-dropdown__menu--BoxShadow);
 7	  }
 8	  &__trigger-background {
 9	    stroke: var(--pf-t--global--BorderColor--100);
10	    fill: var(--pf-t--global--BackgroundColor--light-100);
11	    &.is-disabled {
12	      fill: var(--pf-t--global--color--disabled--300);
13	    }
14	  }
15	  &__trigger-underline {
16	    fill: var(--pf-t--global--Color--100);
17	    &--hover {
18	      fill: var(--pf-t--global--text--color--link--default);
19	    }
20	  }
21	  &__trigger {
22	    font-size: var(--pf-t--global--font--size--md);
23	    text-anchor: middle;
24	    dominant-baseline: middle;
25	    cursor: pointer;
26	  }
27	  &__trigger-disabled {
28	    fill: var(--pf-t--global--text--color--disabled);
29	  }
30	  &__list-items {
31	    max-height: 350px;
32	    overflow: auto;
33	  }
34	  &__divider {
35	    border-color: var(--pf-t--global--border--color--default);
36	    margin: 0;
37	  }
38	  &__render-text {
39	    fill: var(--pf-t--global--text--color--regular);
40	  }
41	}

